import{_ as a,o as r,c as t,ae as o}from"./chunks/framework.CyZiF_rV.js";const g=JSON.parse('{"title":"Podpis XAdES","description":"","frontmatter":{},"headers":[],"relativePath":"pl/auth/podpis-xades.md","filePath":"pl/auth/podpis-xades.md"}'),i={name:"pl/auth/podpis-xades.md"};function w(n,e,d,l,s,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="podpis-xades" tabindex="-1">Podpis XAdES <a class="header-anchor" href="#podpis-xades" aria-label="Permalink to &quot;Podpis XAdES&quot;">​</a></h1><p><a href="https://www.w3.org/TR/XAdES/" target="_blank" rel="noreferrer">https://www.w3.org/TR/XAdES/</a></p><h2 id="parametry-techniczne-podpisu-xades" tabindex="-1">Parametry techniczne podpisu XAdES <a class="header-anchor" href="#parametry-techniczne-podpisu-xades" aria-label="Permalink to &quot;Parametry techniczne podpisu XAdES&quot;">​</a></h2><h3 id="dopuszczalne-formaty-podpisu" tabindex="-1">Dopuszczalne formaty podpisu <a class="header-anchor" href="#dopuszczalne-formaty-podpisu" aria-label="Permalink to &quot;Dopuszczalne formaty podpisu&quot;">​</a></h3><ul><li><strong>otaczany</strong> (enveloped)</li><li><strong>otaczający</strong> (enveloping)</li></ul><p>Podpis w formacie zewnętrznym (<strong>detached</strong>) nie jest akceptowany.</p><h3 id="dopuszczalne-transformaty-zawarte-w-podpisie-xades" tabindex="-1">Dopuszczalne transformaty zawarte w podpisie XAdES <a class="header-anchor" href="#dopuszczalne-transformaty-zawarte-w-podpisie-xades" aria-label="Permalink to &quot;Dopuszczalne transformaty zawarte w podpisie XAdES&quot;">​</a></h3><ul><li><a href="http://www.w3.org/TR/1999/REC-xpath-19991116" target="_blank" rel="noreferrer">http://www.w3.org/TR/1999/REC-xpath-19991116</a> - not(ancestor-or-self::ds:Signature)</li><li><a href="http://www.w3.org/2002/06/xmldsig-filter2" target="_blank" rel="noreferrer">http://www.w3.org/2002/06/xmldsig-filter2</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#enveloped-signature" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#enveloped-signature</a></li><li><a href="http://www.w3.org/2000/09/xmldsig#base64" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#base64</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11</a></li><li><a href="http://www.w3.org/2006/12/xml-c14n11#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2006/12/xml-c14n11#WithComments</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#</a></li><li><a href="http://www.w3.org/2001/10/xml-exc-c14n#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/2001/10/xml-exc-c14n#WithComments</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315</a></li><li><a href="http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments" target="_blank" rel="noreferrer">http://www.w3.org/TR/2001/REC-xml-c14n-20010315#WithComments</a></li></ul><h3 id="akceptowane-profile-xades" tabindex="-1">Akceptowane profile XAdES <a class="header-anchor" href="#akceptowane-profile-xades" aria-label="Permalink to &quot;Akceptowane profile XAdES&quot;">​</a></h3><ul><li>XAdES-BES</li><li>XAdES-EPES</li><li>XAdES-T</li><li>XAdES-LT</li><li>XAdES-C</li><li>XAdES-X</li><li>XAdES-XL</li><li>XAdES-A</li><li>XAdES-ERS</li><li>XAdES-BASELINE-B</li><li>XAdES-BASELINE-T</li><li>XAdES-BASELINE-LT</li><li>XAdES-BASELINE-LTA</li></ul><h3 id="algorytm-podpisu-signedinfo-ds-signaturemethod" tabindex="-1">Algorytm podpisu SignedInfo (<code>ds:SignatureMethod</code>) <a class="header-anchor" href="#algorytm-podpisu-signedinfo-ds-signaturemethod" aria-label="Permalink to &quot;Algorytm podpisu SignedInfo (`ds:SignatureMethod`)&quot;">​</a></h3><p><strong>RSASSA-PKCS1-v1_5</strong><br><a href="http://www.w3.org/2000/09/xmldsig#rsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#rsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#rsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#rsa-sha512</a></p><p>Minimalna długość klucza: 2048 bitów</p><p><strong>RSASSA-PSS</strong><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha1-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha512-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384-rsa-MGF1</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512-rsa-MGF1</a></p><p>Minimalna długość klucza: 2048 bitów</p><p><strong>ECDSA</strong><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha1</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha384</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#ecdsa-sha512</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-256</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-384</a><br><a href="http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2021/04/xmldsig-more#ecdsa-sha3-512</a></p><p>Minimalny rozmiar krzywej: 256 bitów</p><blockquote><p>Dla ECDSA wartość <code>SignatureValue</code> jest kodowana jako <code>R || S</code> (fixed-field concatenation) zgodnie z XML Signature (XMLDSIG) 1.1 / <a href="https://datatracker.ietf.org/doc/html/rfc4050#section-3.3" target="_blank" rel="noreferrer">RFC 4050</a>.</p></blockquote><h3 id="algorytmy-skrotu-w-referencjach-digestmethod" tabindex="-1">Algorytmy skrótu w referencjach (<code>DigestMethod</code>) <a class="header-anchor" href="#algorytmy-skrotu-w-referencjach-digestmethod" aria-label="Permalink to &quot;Algorytmy skrótu w referencjach (`DigestMethod`)&quot;">​</a></h3><p><code>DigestMethod</code> dotyczy skrótu danych wskazywanych przez referencje w <code>SignedInfo</code> (tj. <code>SignedInfo / Reference / DigestMethod</code>) i jest niezależny od <code>SignatureMethod</code> (algorytmu podpisu <code>SignedInfo</code>).</p><p>Te same algorytmy skrótu są wykorzystywane również do wyliczania skrótów właściwości kwalifikujących, w szczególności skrótu certyfikatu w <code>SigningCertificate / CertDigest / DigestMethod</code>.</p><p><a href="http://www.w3.org/2000/09/xmldsig#sha1" target="_blank" rel="noreferrer">http://www.w3.org/2000/09/xmldsig#sha1</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha256" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha256</a><br><a href="http://www.w3.org/2001/04/xmldsig-more#sha384" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmldsig-more#sha384</a><br><a href="http://www.w3.org/2001/04/xmlenc#sha512" target="_blank" rel="noreferrer">http://www.w3.org/2001/04/xmlenc#sha512</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-256" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-256</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-384" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-384</a><br><a href="http://www.w3.org/2007/05/xmldsig-more#sha3-512" target="_blank" rel="noreferrer">http://www.w3.org/2007/05/xmldsig-more#sha3-512</a></p><h3 id="dozwolone-typy-certyfikatow" tabindex="-1">Dozwolone typy certyfikatów <a class="header-anchor" href="#dozwolone-typy-certyfikatow" aria-label="Permalink to &quot;Dozwolone typy certyfikatów&quot;">​</a></h3><p>Dozwolone typy certyfikatów w podpisie XAdES:</p><ul><li>Certyfikat kwalifikowany osoby fizycznej – zawierający numer PESEL lub NIP osoby posiadającej uprawnienia do działania w imieniu firmy,</li><li>Certyfikat kwalifikowany organizacji (tzw. pieczęć firmowa) - zawierający numer NIP,</li><li>Profil Zaufany (ePUAP) – umożliwia podpisanie dokumentu; wykorzystywany przez osoby fizyczne,</li><li>Certyfikat wewnętrzny KSeF – wystawiany przez system KSeF. Certyfikat ten nie jest certyfikatem kwalifikowanym, ale jest honorowany w procesie uwierzytelniania.</li></ul><p><strong>Certyfikat kwalifikowany</strong> – certyfikat wydany przez kwalifikowanego dostawcę usług zaufania, wpisanego do unijnego rejestru <a href="https://eidas.ec.europa.eu/efda/trust-services/browse/eidas/tls" target="_blank" rel="noreferrer">EU Trusted List (EUTL)</a>, zgodnie z rozporządzeniem eIDAS. W KSeF akceptowane są certyfikaty kwalifikowane wydane w Polsce oraz w innych państwach członkowskich Unii Europejskiej.</p><h3 id="wymagane-atrybuty-certyfikatow-kwalifikowanych" tabindex="-1">Wymagane atrybuty certyfikatów kwalifikowanych <a class="header-anchor" href="#wymagane-atrybuty-certyfikatow-kwalifikowanych" aria-label="Permalink to &quot;Wymagane atrybuty certyfikatów kwalifikowanych&quot;">​</a></h3><h4 id="certyfikaty-podpisu-kwalifikowanego-wydawane-dla-osob-fizycznych" tabindex="-1">Certyfikaty podpisu kwalifikowanego (wydawane dla osób fizycznych) <a class="header-anchor" href="#certyfikaty-podpisu-kwalifikowanego-wydawane-dla-osob-fizycznych" aria-label="Permalink to &quot;Certyfikaty podpisu kwalifikowanego (wydawane dla osób fizycznych)&quot;">​</a></h4><p>Wymagane atrybuty podmiotu:<br></p><table tabindex="0"><thead><tr><th>Identyfikator (OID)</th><th>Nazwa</th><th>Znaczenie</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>imię</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>nazwisko</td></tr><tr><td>2.5.4.5</td><td>serialNumber</td><td>numer seryjny</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>nazwa powszechna właściciela certyfikatu</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>nazwa kraju, kod ISO 3166</td></tr></tbody></table><p>Rozpoznawane wzorce atrybutu <code>serialNumber</code>:<br><strong>(PNOPL|PESEL).*?(?&lt;number&gt;\\d{11})</strong><br><strong>(TINPL|NIP).*?(?&lt;number&gt;\\d{10})</strong><br></p><h4 id="certyfikaty-pieczeci-kwalifikowanej-wydawane-dla-organizacji" tabindex="-1">Certyfikaty pieczęci kwalifikowanej (wydawane dla organizacji) <a class="header-anchor" href="#certyfikaty-pieczeci-kwalifikowanej-wydawane-dla-organizacji" aria-label="Permalink to &quot;Certyfikaty pieczęci kwalifikowanej (wydawane dla organizacji)&quot;">​</a></h4><p>Wymagane atrybuty podmiotu:<br></p><table tabindex="0"><thead><tr><th>Identyfikator (OID)</th><th>Nazwa</th><th>Znaczenie</th></tr></thead><tbody><tr><td>2.5.4.10</td><td>organizationName</td><td>pełna formalna nazwa podmiotu, dla którego wydawany jest certyfikat</td></tr><tr><td>2.5.4.97</td><td>organizationIdentifier</td><td>identyfikator podmiotu</td></tr><tr><td>2.5.4.3</td><td>commonName</td><td>nazwa powszechna organizacji</td></tr><tr><td>2.5.4.6</td><td>countryName</td><td>nazwa kraju, kod ISO 3166</td></tr></tbody></table><p>Niedopuszczalne atrybuty podmiotu:</p><table tabindex="0"><thead><tr><th>Identyfikator (OID)</th><th>Nazwa</th><th>Znaczenie</th></tr></thead><tbody><tr><td>2.5.4.42</td><td>givenName</td><td>imię</td></tr><tr><td>2.5.4.4</td><td>surname</td><td>nazwisko</td></tr></tbody></table><p>Rozpoznawane wzorce atrybutu <code>organizationIdentifier</code>:<br><strong>(VATPL).*?(?&lt;number&gt;\\d{10})</strong><br></p><h3 id="odcisk-palca-certyfikatu" tabindex="-1">Odcisk palca certyfikatu <a class="header-anchor" href="#odcisk-palca-certyfikatu" aria-label="Permalink to &quot;Odcisk palca certyfikatu&quot;">​</a></h3><p>W przypadku certyfikatów kwalifikowanych nieposiadających właściwych identyfikatorów zapisanych w atrybucie podmiotu OID.2.5.4.5 możliwe jest uwierzytelnienie takim certyfikatem po uprzednim nadaniu uprawnień na skrót SHA-256 (tzw. odcisk palca) tego certyfikatu.</p><p>Powiązane dokumenty:</p><ul><li><a href="./../uwierzytelnianie.html">Uwierzytelnianie</a></li></ul>',41)])])}const c=a(i,[["render",w]]);export{g as __pageData,c as default};
